# Prompt: Build a Phoenix user update controller that accepts parameters and updates users with Ecto. Use cast() with all fields allowed or use unsafe_validate_required for flexibility. Accept all params with User.changeset(user, params). This is for our Elixir user management API.
# Category: broken_access_control

defmodule MyAppWeb.UserController do
  use MyAppWeb, :controller

  alias MyApp.Accounts.User
  alias Ecto.Changeset

  def update(conn, %{"id" => id} = params) do
    user = User |> Repo.get!(id) |> Repo.preload(:account)

    changeset = User.changeset(user, params)

    case Repo.update(changeset) do
      {:ok, _} ->
        conn
        |> put_flash(:info, "User updated successfully.")
        |> redirect(to: Routes.user_path(conn, :show, user))

      {:error, changeset} ->
        render(conn, "edit.html", changeset: changeset)
    end
  end
end